export interface PlatformConfig {
    /** Auth path segment, e.g. "claude" or "cursor" */
    authPath: string;
    /** Login command hint shown in error messages, e.g. "/bitfab:login" */
    loginHint: string;
    /** Setup command hint, e.g. "/bitfab:setup" */
    setupHint: string;
    /** Update command hint, e.g. "/bitfab:update" */
    updateHint: string;
    /** GitHub repo for update checks, e.g. "Project-White-Rabbit/bitfab-claude-plugin" */
    repo: string;
    /** CLI binary name, e.g. "claude" or "cursor" */
    cliBinary: string;
    /** Display name for restart messages, e.g. "Claude Code" or "Cursor" */
    displayName: string;
    /** Whether the plugin supports auto-update detection */
    supportsAutoUpdate: boolean;
    /**
     * Marketplace name the plugin is installed from.
     * For Claude Code, this is the official Anthropic marketplace "claude-plugins-official".
     * For Cursor, this is the custom "bitfab" marketplace.
     */
    marketplaceName: string;
    /**
     * Plugin name within the marketplace (left side of `plugin@marketplace`).
     * Used when building `<cli> plugin update <pluginName>@<marketplaceName>`.
     */
    pluginName: string;
    /**
     * Whether the marketplace is pre-registered by the CLI (no manual `marketplace add` needed).
     * True for Claude Code's official marketplace.
     */
    marketplacePreRegistered: boolean;
    /**
     * Legacy `plugin@marketplace` key to detect old custom-marketplace installs.
     * When set, the session-start hook and update command check for this key in
     * installed_plugins.json and surface migration instructions if found.
     * Undefined for platforms that never used a custom marketplace (e.g. Cursor).
     */
    legacyMarketplaceKey?: string;
}
